SELECT id, tenant_id, name, description, schema_version, data_source_id, template_config, created_by, created_at, updated_at, is_deleted, deleted_at, status FROM report_metadata WHERE tenant_id = #{tenantId} AND is_deleted = false
AND name LIKE '%' || #{name} || '%'
AND status = #{status}
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM report_metadata WHERE tenant_id = #{tenantId} AND is_deleted = false
AND name LIKE '%' || #{name} || '%'
AND status = #{status}
